  "Do not use color alone for state.": { "zh-CN": "不要只用颜色表达状态。", en: "Do not use color alone for state.", ja: "状態に色だけを使ってはいけません。", ko: "상태를 색상만으로 표현하지 않습니다.", fr: "Ne pas utiliser la couleur seule pour l'état." },
  "Never suppress visible focus.": { "zh-CN": "绝不隐藏可见焦点。", en: "Never suppress visible focus.", ja: "見えるフォーカスを絶対に抑制しません。", ko: "보이는 포커스를 절대 숨기지 않습니다.", fr: "Ne jamais supprimer le focus visible." },
  "Always pair color with text.": { "zh-CN": "颜色始终搭配文本。", en: "Always pair color with text.", ja: "色は常にテキストと組み合わせます。", ko: "색상은 항상 텍스트와 함께 사용합니다.", fr: "Toujours associer la couleur au texte." },
