  "cell focus": { "zh-CN": "单元格焦点", en: "cell focus", ja: "セルフォーカス", ko: "셀 포커스", fr: "focus cellule" },
  "detail panel escape": { "zh-CN": "详情面板退出", en: "detail panel escape", ja: "詳細パネルの Escape", ko: "상세 패널 escape", fr: "échappement panel détail" },
