  "Virtualized lists need keyboard proof": { "zh-CN": "虚拟化列表需要键盘证明", en: "Virtualized lists need keyboard proof", ja: "仮想化リストにはキーボード証明が必要", ko: "가상화 목록에는 키보드 증명이 필요", fr: "Les listes virtualisées nécessitent une preuve clavier" },
  "No filter applied": { "zh-CN": "未应用过滤器", en: "No filter applied", ja: "フィルター未適用", ko: "필터 미적용", fr: "Aucun filtre appliqué" },
  "Remote count unknown": { "zh-CN": "远程数量未知", en: "Remote count unknown", ja: "リモート件数不明", ko: "원격 개수 알 수 없음", fr: "Nombre distant inconnu" },
  "Dashboards": { "zh-CN": "仪表盘", en: "Dashboards", ja: "ダッシュボード", ko: "대시보드", fr: "Dashboards" },
  "Show status before decoration": { "zh-CN": "先展示状态，再做装饰", en: "Show status before decoration", ja: "装飾より先に状態を表示", ko: "장식보다 상태를 먼저 표시", fr: "Afficher le statut avant la décoration" },
  "Evidence links stay separate from readiness claims": { "zh-CN": "证据链接与就绪声明保持分离", en: "Evidence links stay separate from readiness claims", ja: "証拠リンクは準備完了主張から分離", ko: "증거 링크는 준비 주장과 분리", fr: "Les liens de preuve restent séparés des revendications de disponibilité" },
  "Template boundary": { "zh-CN": "模板边界", en: "Template boundary", ja: "テンプレート境界", ko: "템플릿 경계", fr: "Limite de template" },
  "Templates describe layout and interaction rules only; product data truth remains owned by consumer routes.": { "zh-CN": "模板只描述布局和交互规则；产品数据真值仍由消费者路线拥有。", en: "Templates describe layout and interaction rules only; product data truth remains owned by consumer routes.", ja: "テンプレートはレイアウトとインタラクション規則のみを説明し、製品データの真実性は利用側ルートが所有します。", ko: "템플릿은 레이아웃과 상호작용 규칙만 설명하며 제품 데이터 진실성은 소비자 경로가 소유합니다.", fr: "Les templates décrivent uniquement les règles de layout et d'interaction ; la vérité des données produit reste détenue par les routes consommatrices." },
  "State vocabulary": { "zh-CN": "状态词汇", en: "State vocabulary", ja: "状態語彙", ko: "상태 어휘", fr: "Vocabulaire d'état" },
