  "Fixture only": { "zh-CN": "仅示例数据", en: "Fixture only", ja: "フィクスチャのみ", ko: "픽스처 전용", fr: "Fixture seulement" },
  "External proof needed": { "zh-CN": "需要外部证明", en: "External proof needed", ja: "外部証明が必要", ko: "외부 증명 필요", fr: "Preuve externe requise" },
