  "Blocked": { "zh-CN": "已阻止", en: "Blocked", ja: "ブロック中", ko: "차단됨", fr: "Bloqué" },
  "Not claimed": { "zh-CN": "未声明", en: "Not claimed", ja: "未主張", ko: "주장하지 않음", fr: "Non revendiqué" },
