  "Design-system local scaffold": { "zh-CN": "设计系统本地脚手架", en: "Design-system local scaffold", ja: "デザインシステムのローカルスキャフォールド", ko: "디자인 시스템 로컬 스캐폴드", fr: "Scaffold local du design system" },
  "Product adoption not claimed": { "zh-CN": "不声明产品采用", en: "Product adoption not claimed", ja: "製品採用は未主張", ko: "제품 채택 주장 없음", fr: "Adoption produit non revendiquée" },
  "local proof": { "zh-CN": "本地证明", en: "local proof", ja: "ローカル証明", ko: "로컬 증명", fr: "preuve locale" },
  "synthetic examples": { "zh-CN": "合成示例", en: "synthetic examples", ja: "合成例", ko: "합성 예시", fr: "exemples synthétiques" },
  "no raw evidence": { "zh-CN": "无原始证据", en: "no raw evidence", ja: "生の証拠なし", ko: "원시 증거 없음", fr: "aucune preuve brute" },
  "Proof-dependent surfaces must describe the missing proof instead of implying readiness.": { "zh-CN": "依赖证明的界面必须说明缺失证明，而不是暗示已就绪。", en: "Proof-dependent surfaces must describe the missing proof instead of implying readiness.", ja: "証明に依存するサーフェスは準備完了を示唆せず、不足する証明を説明する必要があります。", ko: "증명 의존 화면은 준비 상태를 암시하지 말고 누락된 증명을 설명해야 합니다.", fr: "Les surfaces dépendantes de preuve doivent décrire la preuve manquante plutôt que suggérer la disponibilité." },
  "Proof receipts": { "zh-CN": "证明收据", en: "Proof receipts", ja: "証明レシート", ko: "증명 영수증", fr: "Reçus de preuve" },
  "Receipt": { "zh-CN": "收据", en: "Receipt", ja: "レシート", ko: "영수증", fr: "Reçu" },
  "Storybook static build": { "zh-CN": "Storybook 静态构建", en: "Storybook static build", ja: "Storybook 静的ビルド", ko: "Storybook 정적 빌드", fr: "Build statique Storybook" },
  "local": { "zh-CN": "本地", en: "local", ja: "ローカル", ko: "로컬", fr: "local" },
  "Axe and keyboard checks": { "zh-CN": "Axe 与键盘检查", en: "Axe and keyboard checks", ja: "Axe とキーボードチェック", ko: "Axe 및 키보드 검사", fr: "Contrôles Axe et clavier" },
  "Visual baselines": { "zh-CN": "视觉基线", en: "Visual baselines", ja: "ビジュアルベースライン", ko: "시각 기준선", fr: "Baselines visuelles" },
  "No-overclaim scan": { "zh-CN": "无过度声明扫描", en: "No-overclaim scan", ja: "過剰主張なしスキャン", ko: "과잉 주장 없음 스캔", fr: "Scan sans sur-revendication" },
  "Publication is not routed": { "zh-CN": "发布未被路由", en: "Publication is not routed", ja: "公開はルーティングされていません", ko: "게시가 라우팅되지 않음", fr: "La publication n'est pas routée" },
  "Package publication, GitHub remote creation, and product adoption are blocked in this scaffold route.": { "zh-CN": "此脚手架路线中阻止包发布、GitHub remote 创建和产品采用。", en: "Package publication, GitHub remote creation, and product adoption are blocked in this scaffold route.", ja: "このスキャフォールドルートでは、パッケージ公開、GitHub remote 作成、製品採用がブロックされます。", ko: "이 스캐폴드 경로에서는 패키지 게시, GitHub remote 생성, 제품 채택이 차단됩니다.", fr: "La publication de package, la création de remote GitHub et l'adoption produit sont bloquées dans cette route de scaffold." },
  "Publish": { "zh-CN": "发布", en: "Publish", ja: "公開", ko: "게시", fr: "Publier" },
  "Close": { "zh-CN": "关闭", en: "Close", ja: "閉じる", ko: "닫기", fr: "Fermer" },
  "Action is blocked until an authorized route clears it": { "zh-CN": "操作会保持阻止，直到授权路线解除", en: "Action is blocked until an authorized route clears it", ja: "許可されたルートが解除するまで操作はブロックされます", ko: "승인된 경로가 해제할 때까지 작업은 차단됩니다", fr: "L'action est bloquée jusqu'à validation par une route autorisée" },
  "Open confirmation": { "zh-CN": "打开确认", en: "Open confirmation", ja: "確認を開く", ko: "확인 열기", fr: "Ouvrir la confirmation" },
  "Synthetic confirmation": { "zh-CN": "合成确认", en: "Synthetic confirmation", ja: "合成確認", ko: "합성 확인", fr: "Confirmation synthétique" },
  "Fixture-only confirmation. Product adoption, package publication, and release proof are not claimed.": { "zh-CN": "仅示例确认。不声明产品采用、包发布或发布证明。", en: "Fixture-only confirmation. Product adoption, package publication, and release proof are not claimed.", ja: "フィクスチャのみの確認です。製品採用、パッケージ公開、リリース証明は主張しません。", ko: "픽스처 전용 확인입니다. 제품 채택, 패키지 게시, 릴리스 증명은 주장하지 않습니다.", fr: "Confirmation de fixture seulement. L'adoption produit, la publication de package et la preuve de release ne sont pas revendiquées." },
  "Current checkpoint": { "zh-CN": "当前检查点", en: "Current checkpoint", ja: "現在のチェックポイント", ko: "현재 체크포인트", fr: "Checkpoint actuel" },
  "Checkpoint": { "zh-CN": "检查点", en: "Checkpoint", ja: "チェックポイント", ko: "체크포인트", fr: "Checkpoint" },
  "Storybook IA and governance surface upgrade": { "zh-CN": "Storybook IA 与治理界面升级", en: "Storybook IA and governance surface upgrade", ja: "Storybook IA とガバナンスサーフェスのアップグレード", ko: "Storybook IA 및 거버넌스 화면 업그레이드", fr: "Mise à niveau IA Storybook et surface de gouvernance" },
  "Basis": { "zh-CN": "依据", en: "Basis", ja: "根拠", ko: "근거", fr: "Base" },
  "Owner-approved local implementation route": { "zh-CN": "Owner 批准的本地实现路线", en: "Owner-approved local implementation route", ja: "Owner 承認済みローカル実装ルート", ko: "Owner 승인 로컬 구현 경로", fr: "Route d'implémentation locale approuvée par l'owner" },
  "Boundary": { "zh-CN": "边界", en: "Boundary", ja: "境界", ko: "경계", fr: "Limite" },
  "No package publication, no product adoption, no downstream acceptance claim": { "zh-CN": "不声明包发布、产品采用或下游验收", en: "No package publication, no product adoption, no downstream acceptance claim", ja: "パッケージ公開、製品採用、下流受け入れ主張はありません", ko: "패키지 게시, 제품 채택, 하위 수락 주장이 없습니다", fr: "Aucune publication de package, adoption produit ou revendication d'acceptation aval" },
  "local source change": { "zh-CN": "本地源码变更", en: "local source change", ja: "ローカルソース変更", ko: "로컬 소스 변경", fr: "changement source local" },
