  "The static JSON artifact is the fetchable contract for AI and product implementation agents.": { "zh-CN": "静态 JSON 产物是 AI 和产品实现 agent 可抓取的契约。", en: "The static JSON artifact is the fetchable contract for AI and product implementation agents.", ja: "静的 JSON アーティファクトは、AI と製品実装 agent が取得できる契約です。", ko: "정적 JSON 산출물은 AI 및 제품 구현 agent가 가져올 수 있는 계약입니다.", fr: "L'artefact JSON statique est le contrat récupérable pour les agents IA et implémentation produit." },
  "Blocked claims": { "zh-CN": "被阻止声明", en: "Blocked claims", ja: "ブロックされた主張", ko: "차단된 주장", fr: "Revendications bloquées" },
  "Storybook docs publication": { "zh-CN": "Storybook 文档发布", en: "Storybook docs publication", ja: "Storybook ドキュメント公開", ko: "Storybook 문서 게시", fr: "Publication docs Storybook" },
  "Not claimed by this contract.": { "zh-CN": "此契约不声明。", en: "Not claimed by this contract.", ja: "この契約では主張しません。", ko: "이 계약에서는 주장하지 않습니다.", fr: "Non revendiqué par ce contrat." },
  "Product adoption": { "zh-CN": "产品采用", en: "Product adoption", ja: "製品採用", ko: "제품 채택", fr: "Adoption produit" },
  "Requires a downstream product adoption route.": { "zh-CN": "需要下游产品采用路线。", en: "Requires a downstream product adoption route.", ja: "下流の製品採用ルートが必要です。", ko: "하위 제품 채택 경로가 필요합니다.", fr: "Nécessite une route d'adoption produit aval." },
  "AOS or TMS acceptance": { "zh-CN": "AOS 或 TMS 验收", en: "AOS or TMS acceptance", ja: "AOS または TMS 受け入れ", ko: "AOS 또는 TMS 수락", fr: "Acceptation AOS ou TMS" },
  "Requires product-owned implementation and proof.": { "zh-CN": "需要产品拥有的实现和证明。", en: "Requires product-owned implementation and proof.", ja: "製品所有の実装と証明が必要です。", ko: "제품 소유 구현 및 증명이 필요합니다.", fr: "Nécessite implémentation et preuve possédées par le produit." },
