  "Blocked without Owner Review.": { "zh-CN": "没有 Owner Review 时阻止。", en: "Blocked without Owner Review.", ja: "Owner Review なしではブロックされます。", ko: "Owner Review 없이는 차단됩니다.", fr: "Bloqué sans Owner Review." },
  "220ms emphasized easing": { "zh-CN": "220ms 强调缓动", en: "220ms emphasized easing", ja: "220ms 強調イージング", ko: "220ms 강조 easing", fr: "easing accentué 220 ms" },
  "Unnamed icon action": { "zh-CN": "未命名图标操作", en: "Unnamed icon action", ja: "名前のないアイコン操作", ko: "이름 없는 아이콘 작업", fr: "Action icône sans nom" }
